PyTypeObject* DoInitWrapperWidgetComponent(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperWidgetComponentType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperWidgetComponentPyMethodDefs;
	PyType->tp_getset = FUPyWrapperWidgetComponentGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperWidgetComponent(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(UWidgetComponent::StaticClass(), DoInitWrapperWidgetComponent);
}

FUPyWrapperWidgetComponent* UPyIsWidgetComponent(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperWidgetComponentType))
	{
		return (FUPyWrapperWidgetComponent*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, UWidgetComponent*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperWidgetComponent* PyWidgetComponent = UPyIsWidgetComponent(PyObj))
		{
			if (!FUPyWrapperObject::ValidateInternalState(PyWidgetComponent))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PyWidgetComponent->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'UWidgetComponent'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
